import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useApp } from '../context/AppContext';
import { 
  ShoppingBag, 
  Search, 
  User, 
  Heart, 
  Menu,
  LogOut,
  LayoutDashboard,
  Sun,
  Moon,
  X
} from 'lucide-react';

const Navbar = () => {
  const { user, cartCount, logout, t, theme, toggleTheme } = useApp();
  const navigate = useNavigate();
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  return (
    <>
      <nav className={`navbar ${isScrolled ? 'scrolled' : ''}`}>
        <div className="container nav-container">
          <Link to="/" className="nav-logo">
            <ShoppingBag size={28} strokeWidth={2.5} />
            <span>ShopSRY</span>
          </Link>

          <div className="nav-menu">
            <Link to="/" className="nav-link active">{t('nav_home')}</Link>
            <Link to="/products" className="nav-link">{t('nav_shop')}</Link>
            <Link to="/#categories" className="nav-link">{t('nav_categories')}</Link>
            <Link to="/#about" className="nav-link">{t('nav_about')}</Link>
            <Link to="/#contact" className="nav-link">{t('nav_contact')}</Link>
          </div>

          <div className="nav-actions">
            <button onClick={toggleTheme} className="nav-btn theme-toggle">
              {theme === 'light' ? <Moon size={22} /> : <Sun size={22} />}
            </button>

            <Link to="/wishlist" className="nav-btn">
              <Heart size={22} />
            </Link>

            <Link to="/cart" className="nav-btn">
              <ShoppingBag size={22} />
              {cartCount > 0 && <span className="badge">{cartCount}</span>}
            </Link>

            {user ? (
              <div className="user-profile" style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
                <Link to="/profile" className="nav-btn-profile" title={t('profile')}>
                  <div style={{ 
                    width: '32px', height: '32px', borderRadius: '50%', overflow: 'hidden', 
                    border: '2px solid rgba(0,0,0,0.05)', background: '#eee', flexShrink: 0,
                    display: 'flex', alignItems: 'center', justifyContent: 'center'
                  }}>
                    <img 
                      src={user.image ? (user.image.startsWith('http') ? user.image : `http://localhost:5001${user.image}`) : 'https://img.icons8.com/ios-filled/50/2563eb/user-male-circle.png'} 
                      alt="User" 
                      style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                    />
                  </div>
                </Link>
                {user.role === 'admin' && (
                  <Link to="/admin" className="nav-btn" title={t('admin')}>
                    <LayoutDashboard size={22} color="#2563EB" />
                  </Link>
                )}
                <button onClick={handleLogout} className="nav-btn logout-desktop" title={t('logout')}>
                  <LogOut size={22} />
                </button>
              </div>
            ) : (
              <Link to="/login" className="nav-btn">
                <User size={22} />
              </Link>
            )}

            <button 
              className="nav-btn mobile-menu-btn" 
              onClick={() => setIsMobileMenuOpen(true)}
              style={{ display: 'none' }}
            >
              <Menu size={24} />
            </button>
          </div>
        </div>
      </nav>

      {/* Mobile Menu Drawer */}
      <div className={`mobile-drawer ${isMobileMenuOpen ? 'open' : ''}`}>
        <div className="drawer-header">
          <Link to="/" className="nav-logo" onClick={() => setIsMobileMenuOpen(false)}>
            <ShoppingBag size={26} />
            <span>ShopSRY</span>
          </Link>
          <button onClick={() => setIsMobileMenuOpen(false)}><X size={24} /></button>
        </div>
        <div className="drawer-body">
          <Link to="/" className="drawer-link" onClick={() => setIsMobileMenuOpen(false)}>{t('nav_home')}</Link>
          <Link to="/products" className="drawer-link" onClick={() => setIsMobileMenuOpen(false)}>{t('nav_shop')}</Link>
          <Link to="/cart" className="drawer-link" onClick={() => setIsMobileMenuOpen(false)}>{t('cart_title')}</Link>
          {user && (
            <>
              <Link to="/profile" className="drawer-link" onClick={() => setIsMobileMenuOpen(false)}>{t('profile')}</Link>
              <button className="drawer-link" onClick={() => { handleLogout(); setIsMobileMenuOpen(false); }}>{t('logout')}</button>
            </>
          )}
        </div>
      </div>
      {isMobileMenuOpen && <div className="drawer-overlay" onClick={() => setIsMobileMenuOpen(false)}></div>}
    </>
  );
};

export default Navbar;
